class StateModel:
    def __init__(self, width, height, polyominoes):
        self.width = width
        self.height = height
        self.polyominoes = polyominoes
        self.prob_map = [[0.0 for _ in range(width)] for _ in range(height)]
        self.is_drilled = [[False for _ in range(width)] for _ in range(height)]
        self.is_oil = [[False for _ in range(width)] for _ in range(height)]
        self.possible_placements = self._precompute_placements()

    def _precompute_placements(self):
        placements = []
        for poly in self.polyominoes:
            for r in range(self.height):
                for c in range(self.width):
                    cells = []
                    valid = True
                    for dr, dc in poly:
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < self.height and 0 <= nc < self.width:
                            cells.append((nr, nc))
                        else:
                            valid = False
                            break
                    if valid:
                        placements.append(set(cells))
        return placements

    def update_probabilities(self, observed_cells):
        for r in range(self.height):
            for c in range(self.width):
                count = 0
                for p in self.possible_placements:
                    if (r, c) in p:
                        consistent = True
                        for orr, oc in observed_cells:
                            if (orr, oc) not in p:
                                pass
                        count += 1
                self.prob_map[r][c] = count / len(self.possible_placements) if self.possible_placements else 0

class HeuristicEngine:
    def __init__(self, model):
        self.model = model

    def select_next_probe(self):
        best_cell = (0, 0)
        max_val = -1.0
        for r in range(self.model.height):
            for c in range(self.model.width):
                if not self.model.is_drilled[r][c]:
                    val = self.model.prob_map[r][c]
                    if val > max_val:
                        max_val = val
                        best_cell = (r, c)
        return best_cell
